# https://leetcode.com/problems/daily-temperatures
def dailyTemperatures(temperatures: list[int]) -> list[int]:
    n = len(temperatures)
    stack = []
    result = [0] * n

    for i in range(n - 1, -1, -1):
        while stack and (temperatures[i] >= temperatures[stack[-1]]):
            stack.pop()

        if stack:
            result[i] = stack[-1] - i

        stack.append(i)

    return result


